palette    = pc.qualitative.Plotly + pc.qualitative.D3 + pc.qualitative.Set2
palette    = (palette * 4)[:len(all_voci)]
voce_color = {voce: palette[i] for i, voce in enumerate(all_voci)}

def to_rgba(color, alpha):
    if color.startswith('#'):
        r, g, b = int(color[1:3], 16), int(color[3:5], 16), int(color[5:7], 16)
    else:
        nums = re.findall(r'\d+', color)
        r, g, b = int(nums[0]), int(nums[1]), int(nums[2])
    return f'rgba({r},{g},{b},{alpha})'

def ci_fill(fig, x_fwd, x_rev, hi, lo, color, pattern_shape, alpha_bg, alpha_fg, legendgroup, yaxis):
    fig.add_trace(go.Scatter(
        x=x_fwd + x_rev, y=hi + lo,
        fill='toself',
        fillcolor=to_rgba(color, alpha_bg),
        fillpattern=dict(shape=pattern_shape, fgcolor=to_rgba(color, alpha_fg), size=8, solidity=0.3),
        line=dict(color='rgba(0,0,0,0)'),
        legendgroup=legendgroup, showlegend=False, hoverinfo='skip', yaxis=yaxis,
    ))

