        cx = list(hist['date']) + (list(pred['date'].iloc[:1]) if not pred.empty else [])
        cy = list(hist['NetAmount']) + (list(pred['NetAmount'].iloc[:1]) if not pred.empty else [])
        fig.add_trace(go.Scatter(
            x=cx, y=cy, mode='lines', name=voce,
            legendgroup=lg, legendgrouptitle_text=voce, showlegend=True,
            line=dict(color=color, width=2, shape='spline'), yaxis=yaxis,
        ))
        traces_by_group[lg].append(trace_idx); trace_idx += 1

    if not pred.empty:
        d_fwd = list(pred['date'])
        d_rev = list(pred['date'])[::-1]
        ci_fill(fig, d_fwd, d_rev, list(pred['hi_2s']), list(pred['lo_2s'])[::-1],
                color, '/', 0.08, 0.40, lg, yaxis)
        traces_by_group[lg].append(trace_idx); trace_idx += 1
        ci_fill(fig, d_fwd, d_rev, list(pred['hi_1s']), list(pred['lo_1s'])[::-1],
                color, '/', 0.18, 0.60, lg, yaxis)
        traces_by_group[lg].append(trace_idx); trace_idx += 1
        px = ([hist['date'].iloc[-1]] if not hist.empty else []) + d_fwd
