        fig.add_trace(go.Scatter(
            x=px, y=py, mode='lines', name='forecast', legendgroup=lg,
            line=dict(color=color, width=2, dash='dash', shape='spline'), yaxis=yaxis, showlegend=True,
        ))
        traces_by_group[lg].append(trace_idx); trace_idx += 1

    if not wi.empty:
        d_fwd_w = list(wi['date'])
        d_rev_w = list(wi['date'])[::-1]
        ci_fill(fig, d_fwd_w, d_rev_w, list(wi['hi_2s']), list(wi['lo_2s'])[::-1],
                color, '\\', 0.08, 0.40, lg, yaxis)
        traces_by_group[lg].append(trace_idx); trace_idx += 1
        ci_fill(fig, d_fwd_w, d_rev_w, list(wi['hi_1s']), list(wi['lo_1s'])[::-1],
                color, '\\', 0.18, 0.60, lg, yaxis)
        traces_by_group[lg].append(trace_idx); trace_idx += 1
        wx = ([hist['date'].iloc[-1]] if not hist.empty else []) + d_fwd_w
