            line=dict(color=color, width=2, dash='dot', shape='spline'), yaxis=yaxis, showlegend=True,
        ))
        traces_by_group[lg].append(trace_idx); trace_idx += 1

# ── Separatore storico / forecast ─────────────────────────────────────────────
first_pred = monthly[monthly['predizione']].sort_values('date')
if not first_pred.empty:
    sep = first_pred['date'].iloc[0].strftime('%Y-%m-%d')
