import re
import pandas as pd

pwd = os.environ.get('PWD', '')
friday_root = os.path.dirname(pwd)

# Percorsi alternativi da provare
possible_dirs = [
    os.path.join(friday_root, 'agents/what-if/reports'),
    os.path.join(pwd, 'agents/what-if/reports'),
    os.path.join(pwd, 'reports'),
]

reports_dir = None
