    if os.path.exists(path):
        reports_dir = path
        break

if not reports_dir:
    reports_dir = os.path.join(friday_root, 'agents/what-if/reports')

BT3 = chr(96) * 3
pattern_code = re.compile(BT3 + r'python\s*\n([\s\S]*?)' + BT3)
pattern_req = re.compile(r'##\s*Richiesta\s*\n\s*>\s*(.+)')
pattern_truncate = re.compile(r'([\s\S]*?)(?=\n\s*##\s*Matrice di Perturbazione)', re.IGNORECASE)

runs = []
try:
    if os.path.exists(reports_dir):
        files = sorted(os.listdir(reports_dir), reverse=True)
        for fname in files:
            if not fname.endswith('.md'):
                continue
            fpath = os.path.join(reports_dir, fname)
            try:
                with open(fpath, 'r', encoding='utf-8') as f:
                    content = f.read()

                trunc_match = pattern_truncate.match(content)
                markdown_truncated = trunc_match.group(1).rstrip() if trunc_match else content

                m = re.match(r'whatif_(\d{4})(\d{2})(\d{2})_(\d{2})(\d{2})(\d{2})\.md', fname)
