                    y, mo, d, h, mi, s = m.groups()
                    ts = f"{y}-{mo}-{d}T{h}:{mi}:{s}"
                    label = f"{d}/{mo}/{y} {h}:{mi}"
                else:
                    ts = ''
                    label = fname

                req_match = pattern_req.search(content)
                request_text = req_match.group(1).strip() if req_match else ''

                perturb_data = None
                code_match = pattern_code.search(content)
                if code_match:
                    perturb_code = code_match.group(1).strip()
                    try:
                        local_ns = {'pd': pd}
                        exec(perturb_code, local_ns)
                        result_df = local_ns.get('result')
                        if result_df is not None and hasattr(result_df, 'reset_index'):
                            df_reset = result_df.reset_index()
                            df_reset.columns = ['NumeroConto'] + list(df_reset.columns[1:])
                            perturb_data = df_reset.to_dict('records')
